import React, { useState, useEffect } from 'react';
import './UserProfileCard.css';

interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
  isActive: boolean;
}

interface UserProfileCardProps {
  className?: string;
}

const UserProfileCard: React.FC<UserProfileCardProps> = ({ className }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchUserData = async () => {
      try {
        setLoading(true);
        setError(null);

        const response = await fetch('/api/v1/users/me');

        if (!response.ok) {
          throw new Error(`Failed to fetch user data: ${response.status}`);
        }

        const userData: User = await response.json();
        setUser(userData);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An unknown error occurred');
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, []);

  if (loading) {
    return (
      <div className={`user-profile-card loading ${className || ''}`}>
        <div className="avatar-skeleton" />
        <div className="content-skeleton">
          <div className="name-skeleton" />
          <div className="email-skeleton" />
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className={`user-profile-card error ${className || ''}`}>
        <div className="error-content">
          <span className="error-icon">⚠️</span>
          <p className="error-message">{error}</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className={`user-profile-card error ${className || ''}`}>
        <p>No user data available</p>
      </div>
    );
  }

  return (
    <div 
      className={`user-profile-card ${user.isActive ? 'active' : 'inactive'} ${className || ''}`}
    >
      <div className="avatar-container">
        <img 
          src={user.avatar} 
          alt={`${user.name}'s avatar`}
          className="avatar"
          onError={(e) => {
            const target = e.target as HTMLImageElement;
            target.src = '/default-avatar.png';
          }}
        />
        <div className={`status-indicator ${user.isActive ? 'online' : 'offline'}`} />
      </div>

      <div className="user-info">
        <h3 className="user-name">{user.name}</h3>
        <p className="user-email">{user.email}</p>
        <span className={`status-badge ${user.isActive ? 'active' : 'inactive'}`}>
          {user.isActive ? 'Active' : 'Inactive'}
        </span>
      </div>
    </div>
  );
};

export default UserProfileCard;
